B.acW=new A.a8(B.Eo,["Po\u0142\u0105cz Booking.com","Po\u0142\u0105cz swoje og\u0142oszenie Booking.com, aby Cabinly m\xf3g\u0142 odczytywa\u0107 dost\u0119pno\u015b\u0107 i synchronizowa\u0107 kalendarze. To pomaga zapobiega\u0107 podw\xf3jnym rezerwacjom i daje pe\u0142ny obraz tego, co jest ju\u017c zarezerwowane.","URL Twojego og\u0142oszenia Booking.com","Og\u0142oszenie zidentyfikowane. Nast\u0119pny krok: potwierd\u017a po\u0142\u0105czenie w Booking.com.","Aby doko\u0144czy\u0107 po\u0142\u0105czenie:","Zaloguj si\u0119 do ekstranetu Booking.com","Kliknij awatar swojego profilu w prawym g\xf3rnym rogu","Przejd\u017a do Dostawca \u0142\u0105czno\u015bci","Wyszukaj Cabinly i potwierd\u017a po\u0142\u0105czenie","Wr\xf3\u0107 tutaj, aby kontynuowa\u0107","Otw\xf3rz ekstranet Booking.com","Sprawdzanie po\u0142\u0105czenia...","Po\u0142\u0105czenie zweryfikowane pomy\u015blnie!","Prosz\u0119 doko\u0144czy\u0107 po\u0142\u0105czenie w ekstranecie Booking.com","Nie uda\u0142o si\u0119 zweryfikowa\u0107 po\u0142\u0105czenia. Spr\xf3buj ponownie."],t.w)
B.ab2=new A.a8(B.Em,["Po\u0142\u0105cz swoje \u017ar\xf3d\u0142a rezerwacji","Po\u0142\u0105cz platformy, z kt\xf3rych ju\u017c korzystasz, aby Cabinly m\xf3g\u0142 zmapowa\u0107 dost\u0119pno\u015b\u0107 w r\xf3\u017cnych kana\u0142ach. To pomaga nam zrozumie\u0107, kt\xf3re dni s\u0105 zarezerwowane - a kt\xf3re nie.","Booking.com","Airbnb","iCal","Dla platform bez bezpo\u015bredniej integracji.","Po\u0142\u0105czono","Po\u0142\u0105cz","Konfiguruj","Odczytujemy tylko dane o dost\u0119pno\u015bci. Cabinly nigdy nie zmienia cen, dost\u0119pno\u015bci ani rezerwacji w \u017ar\xf3d\u0142ach rezerwacji bez Twojej zgody.",B.acW],t.EU)
